class Solution:
    def minDays(self, n: int) -> int:
        memo = {0: 0}
        def dp(n):
            if n in memo:
                return memo[n]
            res = 1 + dp(n - 1)
            if n % 2 == 0:
                res = min(res, 1 + dp(n // 2))
            if n % 3 == 0:
                res = min(res, 1 + dp(n - 2 * (n // 3)))
            memo[n] = res
            return res
        return dp(n)
